     1→import { OutboxProcessor } from '@modules/events/outbox/decorators/outbox-processor.decorator';
     2→import { DEPOSIT_OUTBOX_QUEUE_NAME } from '../constant';
     3→import {
     4→  DEPOSIT_COMPITED_OUTBOX_EVENT_NAME,
     5→  IDepositCompitedOutboxEventPayload,
     6→} from '../events/deposit.outbox-event';
     7→import { Job } from 'bullmq';
     8→import { WorkerHost } from '@nestjs/bullmq';
     9→import { IOutboxEvent } from '@modules/events/outbox/types/outbox-event';
    10→import { NotificationsService } from '@modules/notifications/services/notifications.service';
    11→import { Logger } from '@nestjs/common';
    12→import { TenantService } from '@modules/tenant/services/tenant.service';
    13→import { DepositProcessor } from './deposit.processor';
    14→
    15→@OutboxProcessor(DEPOSIT_OUTBOX_QUEUE_NAME)
    16→export class DepositeOutboxProcessor extends WorkerHost {
    17→  constructor(
    18→    private readonly depositProcessor: DepositProcessor,
    19→    private readonly notificationService: NotificationsService,
    20→    private readonly tenantService: TenantService,
    21→  ) {
    22→    super();
    23→  }
    24→
    25→  private readonly logger = new Logger(DepositeOutboxProcessor.name);
    26→
    27→  async process(
    28→    job: Job<IOutboxEvent<IDepositCompitedOutboxEventPayload>>,
    29→  ): Promise<void> {
    30→    if (job.name === DEPOSIT_COMPITED_OUTBOX_EVENT_NAME) {
    31→      await this.processDepositCompitedOutbox(job.data.payload).catch(
    32→        (error) => {
    33→          this.logger.error({
    34→            error,
    35→            message: 'Failed to process deposit compited outbox event',
    36→            job: job.data,
    37→          });
    38→        },
    39→      );
    40→    }
    41→  }
    42→
    43→  async processDepositCompitedOutbox(
    44→    payload: IDepositCompitedOutboxEventPayload,
    45→  ): Promise<void> {
    46→    const tenant = await this.tenantService.getTenant(payload.tenantId);
    47→    let message = `Tenant ${tenant.name}.\n`;
    48→    message += `Deposit ${payload.amount} ${payload.currencyCode} ${payload.network}\n`;
    49→    message += `Commission amount: ${payload.commissionAmount}\n`;
    50→    message += `Deposit transaction hash: ${payload.depositTransactionHash}\n`;
    51→
    52→    await this.notificationService.sendNotification(message).catch((error) => {
    53→      this.logger.error({
    54→        error,
    55→        message: 'Failed to send notification',
    56→        depositId: payload.depositId,
    57→      });
    58→    });
    59→    await this.depositProcessor
    60→      .removeRepeatableMonitorJob(payload.monitorJobKey)
    61→      .catch((error) => {
    62→        this.logger.error({
    63→          error,
    64→          message: 'Failed to remove repeatable monitor job',
    65→          depositId: payload.depositId,
    66→        });
    67→      });
    68→  }
    69→}
    70→

