     8→import { SupportedNetworks } from '@modules/networks/types/network.type';
     9→import { Selectable } from 'kysely';
    10→import {
    11→  DepositPoolAccountEntity,
    12→  CurrencyEntity,
    13→} from '@entities/balance.entity';
    14→import Decimal from 'decimal.js';
    15→
    16→@Injectable()
    17→export class DepositPoolMonitoringService {
    18→  constructor(
    19→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    20→    private readonly networksService: NetworksService,
    21→    private readonly currencyService: CurrencyService,
    22→    @Inject(networksConfigs.KEY)
    23→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    24→  ) {
    25→    //this.monitorPoolAccounts(SupportedNetworks.TRON);
    26→  }
    27→  private readonly logger = new Logger(DepositPoolMonitoringService.name);
    28→
    29→  /**
    30→   * Monitors pool accounts and sweeps funds if balance exceeds threshold
    31→   * Sweeps funds keeping min_deposit_pool_account_amount in the pool account
    32→   */
    33→  async monitorPoolAccounts(network: SupportedNetworks): Promise<void> {
    34→    const trx = await this.db.startTransaction().execute();
    35→    try {
    36→      // Get all pool accounts for
    37→      const poolAccounts = await trx
    38→        .selectFrom('depositPoolAccount')
    39→        // for update to prevent concurrent access
    40→        .forUpdate()
    41→        .selectAll()
    42→        .where('network', '=', network)
    43→        .where((eb) =>
    44→          eb.or([
    45→            eb('lastMonitorAt', 'is', null),
    46→            eb('lastMonitorAt', '<', new Date(Date.now() - 15 * 60 * 1000)), // Only check accounts that have not been monitored yet or lastMonitorAt was more then 15 minutes ago
    47→          ]),
    48→        )
    49→        .where((eb) =>
    50→          eb(
    51→            'id',
    52→            'not in',
    53→            eb
    54→              .selectFrom('depositPoolAccountLocks')
    55→              .select('depositPoolAccountId'),
    56→          ),
    57→        )
    58→        .execute();
    59→
    60→      if (poolAccounts.length === 0) {
    61→        this.logger.log({ message: 'No pool accounts to monitor', network });
    62→        await trx.rollback().execute();
    63→        return;
    64→      }
    65→
    66→      this.logger.log({
    67→        message: `Found ${poolAccounts.length} pool accounts to monitor in ${network} network`,
    68→        network,
    69→      });
    70→
    71→      const outstandingAccount =
    72→        await this.networksService.getOutstandingAccountByNetwork(network);
    73→
    74→      if (!outstandingAccount) {
    75→        this.logger.warn({ message: 'Outstanding account not found', network });
    76→        await trx.rollback().execute();
    77→        return;
    78→      }
    79→
    80→      const networkCurrencies = await this.currencyService.getCurrencies({
    81→        network,
    82→      });
    83→
    84→      // Find base currency that matches the network
    85→      const baseCurrency = networkCurrencies.find(
    86→        (c) => !c.contractAddress && c.network === network,
    87→      );
    88→
    89→      // Process each pool account
    90→      for (const poolAccount of poolAccounts) {
    91→        // Get currency information (lockedCurrencyId is guaranteed to be set since we filtered for it)
    92→
    93→        if (!baseCurrency) {
    94→          this.logger.warn({ message: 'Base currency not found', network });
    95→          continue;
    96→        }
    97→
    98→        await this.sweepBalanceIfRequired(
    99→          poolAccount,
   100→          networkCurrencies,
   101→          outstandingAccount,
   102→        ).catch((error) => {
   103→          this.logger.error({
   104→            error,
   105→            message: 'Failed to sweep balance if required',
   106→            poolAccountId: poolAccount.id,
   107→            network,
   108→          });
   109→        });
   110→        await this.topUpIfNeeded(
   111→          poolAccount,
   112→          baseCurrency,
   113→          outstandingAccount,
   114→        ).catch((error) => {
   115→          this.logger.error({
   116→            error,
   117→            message: 'Failed to top up if needed',
   118→            poolAccountId: poolAccount.id,
   119→            network,
   120→          });
   121→        });
   122→
   123→        await trx
   124→          .updateTable('depositPoolAccount')
   125→          .set({
   126→            lastMonitorAt: new Date(),
   127→          })
   128→          .where('id', '=', poolAccount.id)
   129→          .execute();
   130→      }
   131→
   132→      await trx.commit().execute();
   133→    } catch (error) {
   134→      await trx.rollback().execute();
   135→      this.logger.error({
   136→        error,
   137→        message: 'Failed to monitor and sweep pool accounts',
   138→        network,
   139→      });
   140→      throw error;
   141→    }
   142→  }
   143→
   144→  private async sweepBalanceIfRequired(
   145→    poolAccount: Selectable<DepositPoolAccountEntity>,
   146→    networkCurrencies: Selectable<CurrencyEntity>[],
   147→    outstandingAccount: { address: string; privateKey: string },
   148→  ): Promise<void> {
   149→    //const threshold = new Decimal(currency.thresholdPoolAccountBalanceToSweep);
   150→
   151→    for (const currency of networkCurrencies) {
   152→      const balance = await this.networksService.getBalanceByAddress(
   153→        poolAccount.network,
   154→        poolAccount.address,
   155→        currency.contractAddress,
   156→      );
   157→      if (
   158→        balance.found &&
   159→        new Decimal(balance.amount).gt(
   160→          currency.thresholdPoolAccountBalanceToSweep,
   161→        )
   162→      ) {
   163→        const optimalAmount = new Decimal(currency.optimalPoolAccountBalance);
   164→        const sweepAmount = optimalAmount.minus(balance.amount).abs();
   165→
   166→        const date = new Date();
   167→        const indempotencyKey = `monitoring-sweep-${poolAccount.id}-${currency.id}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;
   168→
   169→        await this.networksService.sweepFunds(
   170→          poolAccount.network,
   171→          currency.code,
   172→          {
   173→            fromPrivateKey: poolAccount.privateKey,
   174→            fromAddress: poolAccount.address,
   175→            toAddress: outstandingAccount.address,
   176→            amount: sweepAmount.toString(),
   177→            indempotencyKey,
   178→          },
   179→        );
   180→      }
   181→    }
   182→  }
   183→
   184→  // Use only for base currency
   185→  async topUpIfNeeded(
   186→    poolAccount: Selectable<DepositPoolAccountEntity>,
   187→    currency: Selectable<CurrencyEntity>,
   188→    outstandingAccount: { address: string; privateKey: string },
   189→  ): Promise<void> {
   190→    const balance = await this.networksService.getBalanceByAddress(
   191→      poolAccount.network,
   192→      poolAccount.address,
   193→      null,
   194→    );
   195→    const balanceDecimal = new Decimal(balance.amount);
   196→    if (balanceDecimal.lt(currency.minPoolAccountBalance)) {
   197→      // min = 50, optimal = 250, threshold = 500
   198→      // topup amount = optimal - 40 - min
   199→      const topupAmount = new Decimal(currency.optimalPoolAccountBalance).minus(
   200→        balanceDecimal,
   201→      );
   202→      //console.log('topupAmount', topupAmount.toString());
   203→      const date = new Date();
   204→      const indempotencyKey = `monitoring-topup-${poolAccount.id}-${currency.id}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;
   205→      console.log({ poolAccount, currency, topupAmount });
   206→      await this.networksService.sweepFunds(
   207→        poolAccount.network,
   208→        currency.code,
   209→        {
   210→          fromAddress: outstandingAccount.address,
   211→          fromPrivateKey: outstandingAccount.privateKey,
   212→          toAddress: poolAccount.address,
   213→          amount: topupAmount.toString(),
   214→          indempotencyKey,
   215→        },
   216→      );
   217→    }
   218→  }
   219→}
